import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { listenAuction, placeBid, listenPlayers, listenRecords } from '../firebase/services';
import Countdown from '../components/Countdown';
import toast from 'react-hot-toast';

const BID_INCREMENTS = [500, 1000, 2000];

export default function PlayerDashboard() {
  const { user, playerData, logout } = useAuth();
  const [auction, setAuction] = useState(null);
  const [records, setRecords] = useState([]);
  const [selectedIncrement, setSelectedIncrement] = useState(500);
  const [bidding, setBidding] = useState(false);
  const [tab, setTab] = useState('auction');

  useEffect(() => {
    const unsubs = [listenAuction(setAuction), listenRecords(setRecords)];
    return () => unsubs.forEach(u => u());
  }, []);

  const myNextBid = auction ? auction.currentBid + selectedIncrement : 0;
  const isCurrentLeader = auction?.currentBidder === user?.uid;
  const hasWonThisCycle = playerData?.hasWon;
  // Admin logic: Admins can't bid

const canBid = 
  auction?.active &&           // Auction must be running
  !auction?.closed &&          // Auction must not be ended
  !hasWonThisCycle &&          // Only players who haven't won a previous month can bid
  !isCurrentLeader &&          // Prevent bidding if YOU are already the highest
  !playerData?.isAdmin;        // Admins can never bid

  const handleBid = async () => {
    if (!canBid) return;
    setBidding(true);
    try {
      await placeBid(user.uid, playerData.name, myNextBid, playerData.isAdmin);
      toast.success(`Bid placed: ₹${myNextBid.toLocaleString('en-IN')}`);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setBidding(false);
    }
  };

  return (
    <div className="page">
      <nav className="navbar">
        <div>
          <div className="navbar-brand">🪙 BC Circle</div>
          <div className="navbar-sub">Hello, {playerData?.name}</div>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={logout}>Logout</button>
      </nav>

      <div className="tabs">
        <div className={`tab ${tab === 'auction' ? 'active' : ''}`} onClick={() => setTab('auction')}>Live Auction</div>
        <div className={`tab ${tab === 'history' ? 'active' : ''}`} onClick={() => setTab('history')}>Records</div>
      </div>

      <div className="content-area">
        {tab === 'auction' ? (
          <>
            {!auction?.active && !auction?.closed && (
              <div className="card" style={{ textAlign: 'center', padding: '50px 20px' }}>
                <div style={{ fontSize: '3rem' }}>💤</div>
                <h3>No Active Auction</h3>
                <p style={{ color: 'var(--text-muted)' }}>The admin hasn't started this month's bidding yet.</p>
              </div>
            )}

            {auction?.active && (
              <div className="card">
                <div className="card-header">
                  <span className="badge badge-green">LIVE</span>
                  <Countdown endsAt={auction.endsAt} />
                </div>
                <div className="bid-display" style={{ textAlign: 'center', padding: '20px 0' }}>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>CURRENT BID</div>
                  <h1 style={{ fontSize: '3.5rem', color: 'var(--gold)', margin: '5px 0' }}>₹{auction.currentBid?.toLocaleString('en-IN')}</h1>
                  <p>Winner gets: <b style={{color: 'var(--green)'}}>₹{(auction.totalPool - auction.currentBid).toLocaleString('en-IN')}</b></p>
                  {auction.currentBidderName && (
                    <div className={`status-msg ${isCurrentLeader ? 'leader' : ''}`}>
                      {isCurrentLeader ? "🏅 You are the leader!" : `Leader: ${auction.currentBidderName}`}
                    </div>
                  )}
                </div>

                {!playerData?.isAdmin ? (
                  !hasWonThisCycle ? (
                    <div className="bidding-section">
                      <div className="increment-row" style={{ display: 'flex', gap: '10px', marginBottom: '15px' }}>
                        {BID_INCREMENTS.map(inc => (
                          <button key={inc} className={`btn-opt ${selectedIncrement === inc ? 'active' : ''}`} onClick={() => setSelectedIncrement(inc)}>+₹{inc}</button>
                        ))}
                      </div>
                      <button className="btn btn-primary btn-full" disabled={!canBid || bidding} onClick={handleBid}>
                        {isCurrentLeader ? "Waiting for others..." : `Bid ₹${myNextBid.toLocaleString('en-IN')}`}
                      </button>
                    </div>
                  ) : (
                    <div className="badge badge-gold" style={{ width: '100%', padding: '15px', textAlign: 'center' }}>🏆 You've won this cycle!</div>
                  )
                ) : (
                  <div className="badge badge-muted" style={{ width: '100%', padding: '15px', textAlign: 'center' }}>👁️ Admin View Mode</div>
                )}
              </div>
            )}

            {auction?.closed && (
              <div className="card winner-card" style={{ textAlign: 'center', background: 'var(--bg-raised)' }}>
                <div style={{ fontSize: '2.5rem' }}>🎊</div>
                <h3>{auction.result?.month} Winner</h3>
                <h2 style={{ color: 'var(--gold)' }}>{auction.result?.winnerName}</h2>
                <p>Received: <b>₹{auction.result?.winnerReceives.toLocaleString('en-IN')}</b></p>
              </div>
            )}
          </>
        ) : (
          <div className="card">
            <h3 className="card-title">Monthly Winners</h3>
            <table className="records-table">
              <thead><tr><th>Month</th><th>Winner</th><th>Amount</th></tr></thead>
              <tbody>
                {records.map((r, i) => (
                  <tr key={i}><td>{r.month}</td><td>{r.winnerName}</td><td style={{ color: 'var(--green)' }}>₹{r.winnerReceives.toLocaleString('en-IN')}</td></tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
